import { initTRPC } from '../src';
import { expect, test } from 'vitest';

const t = initTRPC.create();

test('create empty router', () => {
  const router = t.router({});
  expect(router).toBeDefined();
  expect(router._def).toBeDefined();
});

test('router with query procedure', () => {
  const router = t.router({
    hello: t.procedure.query(() => 'world'),
  });
  expect(router._def.procedures.hello).toBeDefined();
});

test('router with mutation procedure', () => {
  const router = t.router({
    create: t.procedure.mutation(() => ({ id: 1 })),
  });
  expect(router._def.procedures.create).toBeDefined();
});
